import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getEventById, getSlotsByEvent } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const TYPE_ICONS  = { MOVIE: '🎬', CONCERT: '🎵', EVENT: '🎪' };
const TYPE_COLOR  = { MOVIE: '#2563a8', CONCERT: '#c97d1a', EVENT: '#1a8f63' };

const EventDetailPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [event, setEvent]           = useState(null);
  const [slots, setSlots]           = useState([]);
  const [loading, setLoading]       = useState(true);
  const [selectedDate, setSelectedDate] = useState('');

  useEffect(() => {
    const load = async () => {
      try {
        const [evRes, slRes] = await Promise.all([
          getEventById(id),
          getSlotsByEvent(id),
        ]);
        const ev = evRes.data?.data || null;
        const sl = Array.isArray(slRes.data?.data) ? slRes.data.data : [];
        setEvent(ev);
        setSlots(sl);
        if (sl.length > 0) setSelectedDate(sl[0].showDate);
      } catch {
        toast.error('Failed to load event details');
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [id]);

  if (loading) return <div className="loading-center"><div className="spinner" /></div>;
  if (!event)  return (
    <div className="empty-state" style={{ marginTop: '80px' }}>
      <div className="empty-state-icon">🎭</div>
      <h3>Event not found</h3>
      <button onClick={() => navigate('/')} className="btn btn-primary" style={{ marginTop: '16px' }}>Back to Browse</button>
    </div>
  );

  const color         = TYPE_COLOR[event.type]  || '#9c9285';
  const icon          = TYPE_ICONS[event.type]  || '🎪';
  const dates         = [...new Set(slots.map((s) => s.showDate))].sort();
  const filteredSlots = selectedDate ? slots.filter((s) => s.showDate === selectedDate) : slots;
  const availableSlots = filteredSlots.filter((s) => s.slotStatus !== 'CANCELLED');

  return (
    <div style={{ background: 'var(--bg-primary)', minHeight: '100vh' }}>

      {/* ── Hero banner ── */}
      <div style={{ background: 'linear-gradient(135deg,#fff8f5 0%,#fef2ea 100%)', borderBottom: '1.5px solid var(--border)', padding: '28px 0 36px' }}>
        <div className="container">
          <button onClick={() => navigate(-1)} className="btn btn-ghost btn-sm" style={{ marginBottom: '18px', paddingLeft: 0 }}>
            ← Back to Browse
          </button>

          <div style={{ display: 'flex', gap: '24px', alignItems: 'flex-start', flexWrap: 'wrap' }}>
            {/* icon */}
            <div style={{ width: 96, height: 96, background: 'white', borderRadius: '18px', border: `2px solid ${color}40`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '44px', boxShadow: 'var(--shadow)', flexShrink: 0 }}>
              {icon}
            </div>

            {/* info */}
            <div style={{ flex: 1 }}>
              <div style={{ display: 'flex', gap: '8px', marginBottom: '12px', flexWrap: 'wrap' }}>
                <span style={{ fontSize: '12px', fontWeight: 700, color, background: `${color}15`, padding: '3px 10px', borderRadius: '20px' }}>
                  {icon} {event.type}
                </span>
                <span style={{ fontSize: '11px', fontWeight: 700, padding: '3px 9px', borderRadius: '20px',
                  background: event.status === 'ACTIVE' ? '#e8fff5' : '#f0f0f0',
                  color:      event.status === 'ACTIVE' ? '#1a8f63' : '#888',
                }}>
                  {event.status}
                </span>
                {event.genre    && <span className="badge badge-muted">{event.genre}</span>}
                {event.language && <span className="badge badge-muted">{event.language}</span>}
              </div>

              <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 'clamp(1.6rem,3vw,2.8rem)', fontWeight: 400, marginBottom: '10px', color: 'var(--text-primary)' }}>
                {event.name}
              </h1>

              {event.summary && (
                <p style={{ color: 'var(--text-secondary)', lineHeight: 1.7, maxWidth: '600px', fontSize: '15px', marginBottom: '14px' }}>
                  {event.summary}
                </p>
              )}

              <div style={{ display: 'flex', gap: '28px', flexWrap: 'wrap' }}>
                {event.duration     && <Detail label="Duration"     value={event.duration} />}
                {event.categoryName && <Detail label="Category"     value={event.categoryName} />}
                {event.organiser?.name && <Detail label="Organiser" value={event.organiser.name} />}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* ── Shows ── */}
      <div className="container" style={{ paddingTop: '36px', paddingBottom: '48px' }}>
        <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '1.8rem', fontWeight: 400, marginBottom: '6px' }}>
          Choose a Show
        </h2>
        <p style={{ color: 'var(--text-muted)', fontSize: '14px', marginBottom: '24px' }}>
          {slots.length} show{slots.length !== 1 ? 's' : ''} available
        </p>

        {slots.length === 0 ? (
          <div className="empty-state">
            <div className="empty-state-icon">📅</div>
            <h3>No Shows Scheduled</h3>
            <p style={{ fontSize: '13px' }}>Check back later for upcoming shows</p>
          </div>
        ) : (
          <>
            {/* Date tabs */}
            <div style={{ display: 'flex', gap: '8px', marginBottom: '28px', overflowX: 'auto', paddingBottom: '6px' }}>
              {dates.map((date) => {
                const d = new Date(date + 'T00:00:00');
                const isSelected = selectedDate === date;
                return (
                  <button key={date} onClick={() => setSelectedDate(date)}
                    style={{ padding: '10px 22px', borderRadius: '10px', border: '1.5px solid', flexShrink: 0, cursor: 'pointer', transition: 'var(--transition)', fontFamily: 'var(--font-body)', fontWeight: 600, fontSize: '13px',
                      borderColor: isSelected ? 'var(--accent)' : 'var(--border)',
                      background:  isSelected ? 'var(--accent-dim)' : 'var(--bg-card)',
                      color:       isSelected ? 'var(--accent)'     : 'var(--text-secondary)',
                      boxShadow:   isSelected ? 'var(--shadow-accent)' : 'var(--shadow-sm)',
                    }}>
                    <div style={{ fontSize: '12px', opacity: 0.7 }}>{d.toLocaleDateString('en-IN', { weekday: 'short' })}</div>
                    <div>{d.toLocaleDateString('en-IN', { day: 'numeric', month: 'short' })}</div>
                  </button>
                );
              })}
            </div>

            {/* Slot grid */}
            {availableSlots.length === 0 ? (
              <div className="empty-state">
                <div className="empty-state-icon">😔</div>
                <h3>No Shows on This Date</h3>
              </div>
            ) : (
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(200px,1fr))', gap: '14px' }}>
                {availableSlots.map((slot) => (
                  <SlotCard key={slot.slotId} slot={slot} onBook={() => {
                    if (!user) { toast.error('Please login to book'); navigate('/login'); return; }
                    navigate(`/book/${slot.slotId}`);
                  }} />
                ))}
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

// ── Slot Card ────────────────────────────────────────────────────────────────
const SlotCard = ({ slot, onBook }) => {
  const isAvailable = slot.slotStatus === 'AVAILABLE';
  const isHousefull = slot.slotStatus === 'HOUSEFULL';

  return (
    <div className="card" style={{ padding: '20px', transition: 'var(--transition)' }}
      onMouseEnter={(e) => { e.currentTarget.style.transform = 'translateY(-2px)'; e.currentTarget.style.boxShadow = 'var(--shadow-lg)'; }}
      onMouseLeave={(e) => { e.currentTarget.style.transform = '';                  e.currentTarget.style.boxShadow = ''; }}
    >
      {/* time */}
      <div style={{ marginBottom: '12px' }}>
        <div style={{ fontFamily: 'var(--font-display)', fontSize: '2rem', fontWeight: 400, color: 'var(--text-primary)', lineHeight: 1 }}>
          {slot.startTime?.slice(0, 5)}
        </div>
        <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '2px' }}>
          ends {slot.endTime?.slice(0, 5)}
        </div>
      </div>

      {/* location */}
      {slot.location?.locName && (
        <div style={{ fontSize: '13px', color: 'var(--text-secondary)', fontWeight: 600, marginBottom: '14px', display: 'flex', alignItems: 'center', gap: '4px' }}>
          📍 {slot.location.locName}
        </div>
      )}

      {/* seats + book */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div style={{ fontSize: '11px', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.5px', fontWeight: 600 }}>Seats</div>
          <div style={{ fontSize: '14px', fontWeight: 700, color: isAvailable ? 'var(--green)' : isHousefull ? 'var(--gold)' : 'var(--text-muted)' }}>
            {isAvailable ? `${slot.seatsLeft} left` : slot.slotStatus}
          </div>
        </div>
        <button onClick={onBook} disabled={!isAvailable} className="btn btn-primary btn-sm"
          style={{ opacity: isAvailable ? 1 : 0.45 }}>
          {isHousefull ? 'Housefull' : 'Book Now'}
        </button>
      </div>
    </div>
  );
};

const Detail = ({ label, value }) => (
  <div>
    <div style={{ fontSize: '11px', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.6px', fontWeight: 600 }}>{label}</div>
    <div style={{ fontSize: '14px', fontWeight: 700, marginTop: '2px', color: 'var(--text-primary)' }}>{value}</div>
  </div>
);

export default EventDetailPage;
